//-------------------------------------------------------------------------
// 신규입력
//-------------------------------------------------------------------------
scwin.f_addRow = function () {
    try{
        let row = $c.data.insertRow($p.getComponentById("gr_draftBorr"));
        ds_draftBorr.setRowPosition(row);
        $c.gus.cfGoPrevPosition(gr_draftBorr, row);
        ds_draftBorr.setCellData(row, "borrKndCd", "05");
        ed_stDt.setValue("");
        ed_endDt.setValue("");

        $c.gus.cfEnableKeyData();
        $c.gus.cfEnableObjects([btn_borrClntNo,btn_acctDeptCd, btn_rcptBankbookNo,ed_borrDt,img_dueDt,btn_AutoCreate])
        $c.gus.cfDisableObjects([ed_txt_bankAcntNo,ed_txt_borrClntNm,ed_ddCntCd,ed_txt_acctDeptNm])
        $c.gus.cfDisableObjects([   btn_New      ,
                                    btn_Update   ,
                                    btn_Delete
                                ]);
        $c.gus.cfEnableObjects([  btn_Save ,btn_AutoCreate     
                              ]);

        $p.setTimeout(function() {
            ed_txt_draftNo.focus();
        }, {"delay":50});
        lc_intPayMthdCd.setSelectedIndex(0);
    } catch (e) {
       console.log("f_addRow : " + e);
    }
};

//-------------------------------------------------------------------------
// 수정
//-------------------------------------------------------------------------
scwin.f_Update = function () {
    try{
        if(ds_draftBorr.getRowCount() <=0){
            $c.win.alert(MSG_CM_ERR_003);
	        return false;
        }
        $c.gus.cfDisableKeyData();
        $c.gus.cfDisableObjects([btn_borrClntNo,btn_acctDeptCd,btn_rcptBankbookNo,ed_ddCntCd,ed_intRt,ed_intAmt,ed_borrDt,img_dueDt,ed_txt_acctDeptNm])
        $c.gus.cfEnableObjects([lc_intPayMthdCd])
        $c.gus.cfDisableObjects([   btn_New      ,
                                    btn_Update   ,
                                    btn_Delete   ,
                                    btn_AutoCreate
                                ]);
        $c.gus.cfEnableObjects([  btn_Save      
                              ]);
    } catch (e) {
       console.log("f_Update : " + e);
    }
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    try{
        if(ds_draftBorr.getModifiedIndex().length==0){
            $c.win.alert($c.data.getMessage(MSG_CM_ERR_001,"자료"));
            return false;
        }

        let ret = await $c.gus.cfValidate([ed_txt_draftNo,ed_borrClntNo,ed_borrDt,ed_borrAmt]);
        if (!ret) {
            return false;
        }
        for (i=0; i< ds_draftBorr.getRowCount(); i++){
            if ( ds_draftBorr.getRowStatus(i) =="C"){
                if (ds_draftBorr.getCellData(i, "borrAmt") =="0"){
                    ds_draftBorr.setRowPosition(i);
                    await $c.gus.cfAlertMsg("금액은(는) 1 이상으로 입력하십시오.");
                    ed_borrAmt.focus();
                    return false;
                }
            }
        }

        let ret2 = await $c.gus.cfValidate([ed_rcptBankbookNo,ed_acctDeptCd,ed_rcptBankbookNo]);

        if (!ret2 ) {
            return false;
        }else{

            if (!$c.gus.cfIsAfterDate(ed_stDt.getValue(), ed_endDt.getValue())) {
                $c.gus.cfAlertMsg(MSG_CM_ERR_039); // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
                return false;
            }

            if ( ds_draftBorr.getRowStatus(ds_draftBorr.getRowPosition()) =="C"){
                sbm_createDraftBorr.action="/ac.fm.fundemploy.borrmgnt.ProcessDraftBorrowingRegistCMD.do";
            }else{
                sbm_createDraftBorr.action="/ac.fm.fundemploy.borrmgnt.UpdateDraftBorrowingCMD.do";
            }

            if(await $c.win.confirm(MSG_CM_CRM_001)) {
                scwin.pos_groupCode = ds_draftBorr.getRowPosition();
                $c.sbm.execute(sbm_createDraftBorr);
            }
        }
    } catch (e) {
       console.log("f_Save : " + e);
    }
};

//-------------------------------------------------------------------------
// 저장콜백
//------------------------------------------------------------------------
scwin.sbm_createDraftBorr_submitdone = function (e) {
    try{
        if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail
        $c.gus.cfAlertMsg(MSG_CM_INF_001);
        scwin.f_Retrieve();
        $c.gus.cfDisableKeyData();
        $c.gus.cfEnableObjects([   btn_New     ,
                                btn_Update  ,
                                btn_Save    ,
                                btn_Delete
                                ]);
    } catch (e) {
       console.log("sbm_createDraftBorr_submitdone : " + e);
    }
};

//-------------------------------------------------------------------------
// 삭제
//-------------------------------------------------------------------------
scwin.f_Delete = async function () {
    try{
        let sSlipNo = "";
        if(ds_draftBorr.getRowCount() <=0) {
            $c.win.alert($c.data.getMessage(MSG_CM_WRN_004,"자료"));
            return false;
        }else{
            let ret = await $c.gus.cfValidate([gr_draftBorr]);
            if (!ret ) {
                return false;
            }

            if(await $c.win.confirm(MSG_CM_CRM_004)) {
                sSlipNo = ds_draftBorr.getCellData(ds_draftBorr.getRowPosition(), "borrSlipNo");
                ds_deleteDraftBorrCondition.set("slipNumber", sSlipNo);
                ds_draftBorr.deleteRows(ds_draftBorr.getRowPosition());
                sbm_deleteDraftBorr.action = "/ac.fm.fundemploy.borrmgnt.ProcessDraftBorrowingDeleteCMD.do";
                $c.sbm.execute(sbm_deleteDraftBorr);
            }
        }

    } catch (e) {
       console.log("f_Delete : " + e);
    }
};

//-------------------------------------------------------------------------
// 삭제콜백
//------------------------------------------------------------------------
scwin.sbm_deleteDraftBorr_submitdone = function (e) {
    try{
        if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail
        $c.gus.cfAlertMsg(MSG_CM_INF_004);
        scwin.pos_groupCode = 0;
        scwin.f_Retrieve();
        $c.gus.cfDisableKeyData();
        $c.gus.cfEnableObjects([    btn_New     ,
                                    btn_Update  ,
                                    btn_Delete
                                ]);
        $c.gus.cfDisableObjects([   btn_Save     
						        ]);
    } catch (e) {
       console.log("sbm_deleteDraftBorr_submitdone : " + e);
    }
};

scwin.ds_draftBorr_oncelldatachange = function (info) {
    try{
        let colid = info.colID;
        let row = info.rowIndex;

        if ( colid == "stDt" || colid == "endDt")
        {
            if ( !(( ds_draftBorr.getCellData(row,"stDt") == null || ds_draftBorr.getCellData(row,"stDt") == "" ) ||
                ( ds_draftBorr.getCellData(row,"endDt") == null  || ds_draftBorr.getCellData(row,"endDt") == "" )))
            {
                if ( ds_draftBorr.getCellData(row,"stDt").trimAll().length == 8 && 
                    ds_draftBorr.getCellData(row,"endDt").trimAll().length == 8 )
                {
                    ds_draftBorr.setCellData(row,"ddCntCd", $c.date.diffDate(ds_draftBorr.getCellData(row,"stDt").trimAll(), ds_draftBorr.getCellData(row,"endDt").trimAll()) + 1);
                }
            } else{
                ds_draftBorr.setCellData(row,"ddCntCd",0);
            }
        }else if ( colid == "borrAmt" || colid == "intRt")
        {
            ds_draftBorr.setCellData(row,"intAmt",Math.floor((0.01 * ds_draftBorr.getCellData(row,"borrAmt") *   ds_draftBorr.getCellData(row,"intRt") * ds_draftBorr.getCellData(row,"ddCntCd")) / 365 )) 
        }
    } catch (e) {
       console.log("ds_draftBorr_oncelldatachange : " + e);
    }    
};

scwin.gr_draftBorr_onrowindexchange = function (rowIndex, oldRow) {
    if(ds_draftBorr.getRowStatus(rowIndex) =="R"){
        $c.gus.cfDisableKeyData();
    } else if(ds_draftBorr.getRowStatus(rowIndex) =="C"){
        $c.gus.cfEnableKeyData();
    }
};
